CLUSTER:
[
 {
  "riskId": "risk.demand-discontinuity.construction-plateau-lumpy-year1",
  "title": "Construction has plateaued while the pipeline balloons: Year-1 opens onto a digestion trough the 9% trend averages away",
  "narrative": "EMEA capacity under construction has plateaued at ~2.5 GW even as the development pipeline swelled 25% to nearly 15 GW — projects are stacking in planning, not converting to builds, because grid, permits and capex phasing bind. PDU purchase orders follow construction fit-out, not pipeline announcements. And with public cloud providers taking 61% of 2025 EMEA take-up, three or four hyperscaler capex committees synchronize the whole cycle: if 2026 is an AI-capex digestion year, CE fit-out starts pause for 2–4 quarters exactly inside the venture's window while the 2030 CAGR remains intact on paper. The 1%-of-SAM Year-1 anchor implicitly assumes an on-trend year; the conversion data says the window may be a below-trend one.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "EMEA under-construction capacity plateaued at ~2.5 GW while the pipeline grew >25% to ~15 GW — the planning-to-construction conversion, not demand, is the binding constraint",
    "refs": [
     "digest:geo-NL#c3",
     "digest:geo-NL#c2"
    ]
   },
   {
    "step": "propagation",
    "text": "Public cloud accounts for ~61% of EMEA take-up, so a synchronized capex digestion by a handful of buyers stalls CE fit-out starts for multiple quarters; PDU orders are placed at fit-out, so Year-1 order flow decouples from the 8–10% trend consensus that the model treats as context",
    "refs": [
     "digest:geo-DE#c18",
     "ledger:shape.cagr"
    ]
   },
   {
    "step": "model-impact",
    "text": "obtainableFactor's 1%-of-SAM anchor presumes an average demand year; a trough year roughly halves the achievable Year-1 pace without changing TAM or SAM at all",
    "refs": [
     "ledger:obtainableFactor"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "European data-center capex commentary and guidance from the top cloud buyers",
    "where": "Microsoft/Alphabet/Amazon/Meta quarterly earnings calls, EU infrastructure line items",
    "threshold": "Two or more guiding EU DC capex flat-to-down for 2026",
    "updates": "increases"
   },
   {
    "signal": "EMEA under-construction capacity metric",
    "where": "Cushman & Wakefield EMEA data centre update (half-yearly)",
    "threshold": "UC stuck at ≤2.5 GW for two consecutive prints while pipeline keeps growing",
    "updates": "increases"
   }
  ],
  "judgeTotal": 16
 },
 {
  "riskId": "risk.regulatory-gauntlet.avl-framework-qualification-forecloses-large-operator-cell",
  "title": "Buyer-side procurement norms (AVL qualification, ISO 27001/IEC 62443 attestations, global frameworks) close the chosen 40% large-operator beachhead for the entire Year-1 window",
  "narrative": "The venture's stated beachhead is large operators — modeled as 40% of PDU spend. But that cell is not entered by winning a bake-off; it is entered by surviving an approved-vendor-list qualification: vendor security questionnaires demanding ISO 27001 and secure-development (IEC 62443-4-1) attestations, TÜV/CB-scheme type-test reports, factory audits, and financial-viability checks — a 12–18 month cycle that no law mandates and no market report prices. On top of that, the corpus shows the cell's spend is increasingly channelled through multi-year global frameworks (Digital Realty's $373M Schneider agreement, Iren's all-in Dell contract) and integrator bundles, meaning much of the nominal 0.40 is never tendered at PDU line-item level at all. The 0.40 value is an unsourced internal estimate; the reachable-in-window fraction of it is far smaller. The model books the beachhead as the largest cell; procurement norms make it the slowest.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "Large-operator procurement requires AVL qualification artifacts (ISO 27001 / secure-development attestations, TÜV/CB reports, audits) that a pre-launch entrant does not yet hold — a buyer-side norm, not a legal instrument, so it appears on no regulatory checklist",
    "refs": [
     "profile:Company",
     "ledger:cust.operator-large",
     "digest:serviceable-benchmark#c13"
    ]
   },
   {
    "step": "propagation",
    "text": "The spend that does move moves through global frameworks and integrator bundles rather than contestable PDU line items — the corpus documents Digital Realty/Schneider, Iren/Dell and Jülich-style bundling — so even qualified challengers see few discrete PDU decisions in a 12-month window",
    "refs": [
     "digest:refine-structure-independence.global-framework-forecloses-large-operator-cell#c0",
     "digest:refine-boundary-substitution.large-operator-channel-forecloses-to-odm#c0",
     "digest:cust-mix#c0"
    ]
   },
   {
    "step": "model-impact",
    "text": "The contestable large-operator cell is materially below 0.40 and the Year-1 pace within it approaches zero; since this is the declared primary channel, the YAM is effectively being earned from the other 60% of the buyer mix",
    "refs": [
     "ledger:cust.operator-large",
     "ledger:obtainableFactor",
     "profile:Product"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "AVL qualification requirements and cycle times quoted in operator supplier-onboarding portals",
    "where": "Equinix/Digital Realty/NTT GDC supplier registration portals; Vantage/CyrusOne EU procurement contacts",
    "threshold": "Mandatory ISO 27001 or 12+ month qualification stated for electrical-fit-out vendors",
    "updates": "increases"
   },
   {
    "signal": "Share of PDU spend announced inside multi-year framework or integrated-rack deals",
    "where": "Operator capex calls and press releases (Digital Realty, Iren-class contracts); Schneider/Vertiv earnings commentary on framework backlog",
    "threshold": "≥1 new CE operator announcing a global power-train framework covering rack PDUs",
    "updates": "increases"
   }
  ],
  "judgeTotal": 17
 },
 {
  "riskId": "risk.execution-window.som-window-semantics-year1-zero",
  "title": "The 1% Year-1 anchor is a 36-month accrual read as an annual snapshot — the pre-launch clock makes even that generous",
  "narrative": "obtainableFactor's 1% was 'corrected' in refinement cycle 1 and now looks conservative and triangulated. But the benchmark corpus it leans on defines SOM as a 1–3 year (Prospeo, IdeaPlan) or 3–5 year (Wise) cumulative capture, not a Year-1 run-rate, and the one worked example in the corpus lands at 0.1% of SAM — 5x below the band's own floor. Layer the venture's actual clock on top: it is pre-launch, so months 1–6 are certification, listing and pipeline-building, not selling. A 'conservative ramp' that books its first PO in month 7–9 doesn't earn 1% of SAM; it earns a fraction of the back half of the year. The band's low edge (0.5%) is not the pessimistic case — it is the optimistic reading of the sources' own semantics.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "The Prospeo/IdeaPlan/Wise benchmark family defines the 1–5% obtainable share as accruing over 1–3 or 3–5 years, not per-year; the ledger pins 1% strictly to Year 1",
    "refs": [
     "digest:obtainable-benchmark#c1",
     "digest:obtainable-benchmark#c5",
     "digest:obtainable-benchmark#c6",
     "ledger:obtainableFactor"
    ]
   },
   {
    "step": "propagation",
    "text": "The only concrete worked example in the corpus yields SOM/SAM ≈ 0.1% ($3.2M/$3.2B) for years 1–2, and the Tractian comparable started at $200K — not the ~$1.2M first-year figure the ledger's crossCheck asserts",
    "refs": [
     "digest:obtainable-benchmark#c7",
     "digest:obtainable-benchmark#c10"
    ]
   },
   {
    "step": "propagation",
    "text": "The venture is pre-launch with a conservative-ramp profile: the selling window inside Year 1 is 6–9 months at best, so any annualized benchmark must be pro-rated before it is applied",
    "refs": [
     "profile:Stage",
     "profile:What obtainable horizon should Year-1 (YAM) assume?"
    ]
   },
   {
    "step": "model-impact",
    "text": "obtainableFactor at 0.01 overstates the realistic Year-1 capture by 2–3x; the defensible point sits at or below the band floor",
    "refs": [
     "ledger:obtainableFactor"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "Months from launch to first booked CE purchase order",
    "where": "Own CRM plus TED (EU public tender portal) responses to rack-power lots the venture bids",
    "threshold": "No PO by month 6 post-launch",
    "updates": "increases"
   },
   {
    "signal": "First-year revenue disclosures of comparable rack-power/DC-hardware entrants",
    "where": "Crunchbase/annual filings of recent PDU or rack-infrastructure startups entering EU",
    "threshold": "Comparables clustering below 0.5% of their stated SAM in year 1",
    "updates": "increases"
   }
  ],
  "judgeTotal": 17
 },
 {
  "riskId": "risk.regulatory-gauntlet.red-en18031-wireless-sensor-gate",
  "title": "RED cybersecurity delegated act (EU 2022/30, applicable since 1 Aug 2025): one WiFi sensor port drags the PDU into EN 18031 conformity and adds two quarters to launch",
  "narrative": "If the intelligent PDU ships with any radio — WiFi management fallback, BLE commissioning, wireless environmental sensors — it is radio equipment, and since 1 August 2025 the Radio Equipment Directive's cybersecurity delegated act applies in full. Conformity runs against EN 18031-1/-2, which are harmonized only WITH RESTRICTIONS: where the restrictions bite (e.g., password/access-control configurations), self-declaration is unavailable and a notified body must issue an EU-type examination certificate. For a pre-launch team this is not a 2027 problem like the CRA — it is a today problem that gates the very first shipment. The obtainableFactor's 1% Year-1 anchor already sits on a corrected, fragile benchmark; a 4–6 month notified-body queue on top of an already pre-let, slow-procurement market compresses the sellable window from 12 months to 6–8.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "The launch configuration includes a radio (wireless sensors / BLE commissioning), pulling the product under the RED cybersecurity delegated act — in force since 1 Aug 2025, i.e., before the venture's first shipment",
    "refs": [
     "profile:Product",
     "profile:Stage"
    ]
   },
   {
    "step": "propagation",
    "text": "EN 18031's harmonization restrictions force notified-body involvement for common access-control configurations; certificate lead time lands mid-window, and the market's own procurement clock (gear locked 12–24+ months pre-fit-out, few contestable standalone tenders) means a late start forfeits most Year-1 bake-offs",
    "refs": [
     "digest:refine-demand-discontinuity.prelet-pipeline-lockout#c0",
     "digest:refine-competitive-foreclosure.bundling-eliminates-bakeoffs-year1#c2",
     "ledger:obtainableFactor"
    ]
   },
   {
    "step": "model-impact",
    "text": "The Year-1 obtainable share, whose 1% value already rests on a benchmark-period correction and a shaky Tractian comparable, is cut roughly in half by a shortened selling window",
    "refs": [
     "ledger:obtainableFactor",
     "digest:obtainable-benchmark#c5",
     "digest:refine-execution-window.som-window-semantics-mismatch#c4"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "EN 18031 harmonization restrictions status (whether the OJ listing's restrictions are lifted or extended)",
    "where": "EU Official Journal harmonized-standards citations under RED; NANDO database queue times for RED cybersecurity notified bodies",
    "threshold": "Notified-body lead quotes >4 months, or restrictions extended into 2026",
    "updates": "increases"
   },
   {
    "signal": "Own-product radio scope decision and test-house booking",
    "where": "Internal launch BOM review; test-house (TÜV/DEKRA) quotation and slot calendar for EN 18031",
    "threshold": "Radio in launch SKU with no notified-body slot booked 9 months pre-launch",
    "updates": "increases"
   }
  ],
  "judgeTotal": 18
 },
 {
  "riskId": "risk.execution-window.prelet-pipeline-lockout",
  "title": "The growth the CAGR promises was electrically specified before launch day — Year 1 can only sell into the installed base",
  "narrative": "Nine percent CAGR reads as a tailwind: new halls, new racks, new PDU line items every quarter of Year 1. But new-build DC electrical procurement is locked at design freeze, and with long-lead power equipment (transformers, switchgear) now booked years out, operators are locking entire electrical BOMs — PDUs riding along — far earlier than the 12–24-month window the ledger's own crossCheck uses to justify its ceiling. Every megawatt that energizes during the venture's first 12 months had its rack-power vendor chosen while the venture was still pre-launch. That leaves Year-1 demand confined to retrofit, refresh and expansion churn in the installed base — a materially smaller and slower pool than 'the market' — while the model applies its 1% to the whole SAM as if new-build spend were reachable on the venture's clock.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "New-build electrical BOMs for capacity energizing in the venture's Year 1 were specified at design freeze, before the venture existed as a qualified vendor; the ledger's own crossCheck concedes gear is 'locked 12–24mo before fit-out' and current long-lead conditions push lock-in earlier still",
    "refs": [
     "ledger:obtainableFactor",
     "profile:Stage"
    ]
   },
   {
    "step": "propagation",
    "text": "The market's growth is concentrated in exactly this pre-committed new-build pipeline (the substance of the 9% CAGR), so the contestable Year-1 pool is the installed base's refresh cycle — and what standalone PDU procurement evidence exists shows small, sometimes sole-sourced lots with 1–2 bidders, not open bake-offs",
    "refs": [
     "ledger:shape.cagr",
     "digest:obtainable-benchmark#c12"
    ]
   },
   {
    "step": "propagation",
    "text": "Generic obtainable-share benchmarks (1% Year 1) assume the full SAM is time-reachable; no DC-hardware-specific benchmark exists that discounts for procurement lock-in, so the model has no mechanism to encode it",
    "refs": [
     "digest:obtainable-benchmark#c0",
     "digest:obtainable-benchmark#c2"
    ]
   },
   {
    "step": "model-impact",
    "text": "obtainableFactor applied to the full SAM double-counts pre-committed new-build spend as reachable; the truly contestable Year-1 share sits at or below the band floor",
    "refs": [
     "ledger:obtainableFactor"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "Stage at which rack-PDU vendor is fixed in CE fit-out tenders (bundled at design freeze vs late separate lot)",
    "where": "TED tender documents for DE/NL data-center fit-outs; fit-out contractors' bid packages",
    "threshold": "PDU line bundled into general-electrical packages in ≥3 of 4 sampled tenders",
    "updates": "increases"
   },
   {
    "signal": "Pre-let percentages and long-lead procurement commentary for CE capacity additions",
    "where": "Operator and hyperscaler capex calls (Equinix, Digital Realty quarterly); Vertiv/Schneider backlog commentary",
    "threshold": "Pre-let >80% with electrical packages cited as booked >18 months out",
    "updates": "increases"
   }
  ],
  "judgeTotal": 17
 },
 {
  "riskId": "risk.demand-discontinuity.prelet-lockout-year1-contestability",
  "title": "83% pre-let pipeline plus long-lead electrical frameworks leave almost no contestable Year-1 PDU orders",
  "narrative": "The obtainableFactor's own cross-check assumes DC electrical gear is locked 12–24 months before fit-out, which keeps a ≤2% Year-1 share plausible. But the FLAP-D development pipeline is 83% pre-let at a record-low 6.3% vacancy — the 2026–27 builds a new entrant would sell into had their electrical bill-of-materials specified inside framework agreements signed at pre-let, i.e. in 2023–24. The venture's first 12 months open onto a market where the visible demand is real but already awarded: what remains contestable is churn and expansion inside operating halls, a fraction of the 1% anchor. The YAM is not conservative; it is counting orders that were signed before the company existed in the market.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "FLAP-D vacancy hits a record-low 6.3% with the pipeline 83% pre-let — capacity is committed to named tenants years before commissioning, and pre-let deals carry integrated electrical packages fixed at design lock",
    "refs": [
     "digest:geo-DE#c19",
     "ledger:obtainableFactor"
    ]
   },
   {
    "step": "propagation",
    "text": "PDU line items ride those pre-let frameworks through the large-operator channel the venture targets first; RFPs that open during the venture's first 12 months are for capacity commissioning in 2028+, not for Year-1 revenue",
    "refs": [
     "ledger:cust.operator-large",
     "digest:geo-DE#c19",
     "profile:Who is the primary buyer you'll sell through first?"
    ]
   },
   {
    "step": "model-impact",
    "text": "The truly contestable Year-1 share of SAM sits below the 0.5% band floor; the 1% Prospeo anchor — already flagged as semantically fragile — overstates the first-year orderbook regardless of SAM size",
    "refs": [
     "ledger:obtainableFactor"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "Share of CE data-center electrical/PDU procurements that are open multi-bidder vs sole-source or framework call-offs",
    "where": "TED (EU tenders portal) and major operator procurement portals (Digital Realty, Equinix, NTT supplier registration)",
    "threshold": "<20% of PDU line items contested openly over two quarters",
    "updates": "increases"
   },
   {
    "signal": "FLAP-D pre-let percentage and vacancy in successive half-year prints",
    "where": "JLL EMEA Data Centre Report and Cushman & Wakefield EMEA updates",
    "threshold": "Pre-let stays above 80% with vacancy below 8%",
    "updates": "increases"
   }
  ],
  "judgeTotal": 17
 },
 {
  "riskId": "risk.base-rate-analogy.som-window-cumulative-misread",
  "title": "The 1% Year-1 anchor is a 36-month number wearing a 12-month label",
  "narrative": "obtainableFactor's 1% rests on Prospeo's staged benchmark, read as an annual snapshot. But Prospeo itself frames SOM as revenue captured over 1-3 years, IdeaPlan says 'one to three years', Wise says 'three to five years', and TryBuildCo's own worked example lands at 0.1% of SAM — below the model's stated floor of 0.5%. The cross-check comparable (Tractian '$1.2M first year') is unverified against its own source, which shows $200K starting revenue. For a pre-launch industrial entrant with zero installed base and no certifications on day 0, the honest 12-month number is the bottom of the reference class, not its midpoint. The whole YAM figure is a period-mismatch error, not a market estimate.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "Every source underlying the 1% benchmark defines the obtainable percentage as a cumulative 1-3 or 3-5 year capture window, not a Year-1 snapshot — the model pins a multi-year ratio to a 12-month YAM",
    "refs": [
     "digest:obtainable-benchmark#c1",
     "digest:obtainable-benchmark#c5",
     "digest:obtainable-benchmark#c6"
    ]
   },
   {
    "step": "propagation",
    "text": "The two cross-checks that were supposed to independently confirm 1% both fail on inspection: TryBuildCo's worked example yields ~0.1% of SAM (below the model's 0.5% floor), and Tractian's revenue started at $200K — the '$1.2M first year' number cited in the derivation does not appear in the source",
    "refs": [
     "digest:obtainable-benchmark#c7",
     "digest:obtainable-benchmark#c10"
    ]
   },
   {
    "step": "model-impact",
    "text": "obtainableFactor 0.01 overstates the honest pre-launch Year-1 capture by roughly 3x; the corrected value sits near 0.3% of SAM, and the sensitivity band's low edge (0.5%) does not even contain the reference-class outcomes",
    "refs": [
     "ledger:obtainableFactor",
     "profile:Stage"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "Quote-to-PO conversion time in the first CE opportunities",
    "where": "Own CRM pipeline reviewed at month 6; cross-referenced against TED (Tenders Electronic Daily) award timelines for rack-power line items",
    "threshold": "Median cycle >9 months at month 6 implies Year-1 closes are structurally impossible at the 1% level",
    "updates": "increases"
   },
   {
    "signal": "Published first-year revenue disclosures of comparable DC-hardware entrants (Asian PDU makers entering EU)",
    "where": "Company registries / Crunchbase / vendor press releases announcing first EU revenue milestones",
    "threshold": "No comparable showing >0.5% regional SAM capture in year 1",
    "updates": "increases"
   }
  ],
  "judgeTotal": 16
 },
 {
  "riskId": "risk.execution-window.firmware-security-audit-gate",
  "title": "The firmware/security audit gate precedes every intelligent-PDU listing — and it isn't in the funnel",
  "narrative": "An intelligent PDU is a networked device sitting on the management LAN of critical infrastructure. Before any large CE operator issues a PO, the vendor must clear a security prequalification that a dumb-metal vendor never faces: vulnerability disclosure process, signed-firmware update infrastructure, SBOM, penetration evidence, increasingly IEC 62443-style artifacts as the EU Cyber Resilience Act obligations phase in. This gate is serial with — not parallel to — CE/TÜV product certification, and it is audited against infrastructure the pre-launch venture has to build during the very year YAM assumes it is harvesting. The serviceableFactor's 0.55 haircut names only the classic cert stack; the security gate is a second, slower door in front of the same customers, and it opens per-operator, not per-product.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "Large-operator prequalification for networked power devices requires an auditable firmware update/PSIRT/SBOM capability before AVL listing; the documented EU entry stack (WEEE, CE, TÜV, RoHS, FCC) is already broader than the ledger's derivation names, and cyber requirements sit on top of it",
    "refs": [
     "digest:serviceable-benchmark#c13",
     "digest:serviceable-benchmark#c4",
     "ledger:serviceableFactor"
    ]
   },
   {
    "step": "propagation",
    "text": "A pre-launch entrant builds this infrastructure and passes per-operator audits inside the same 12 months YAM covers; each audit cycle runs one to two quarters, and the primary-buyer choice (large operators) selects exactly the buyers with the heaviest security gates",
    "refs": [
     "profile:Stage",
     "profile:Who is the primary buyer you'll sell through first?"
    ]
   },
   {
    "step": "model-impact",
    "text": "The gate serially delays the first PO (compressing the effective selling window inside obtainableFactor) and forecloses security-gated accounts entirely for Year 1 (a reach shortfall inside serviceableFactor) — neither effect appears in the static 0.55 or the 1%",
    "refs": [
     "ledger:obtainableFactor",
     "ledger:serviceableFactor"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "Vendor-security questionnaire content (SBOM, signed firmware, PSIRT, 62443 mapping) in rack-power prequalification packets",
    "where": "Procurement/supplier portals of Equinix, Digital Realty, NorthC and other CE colo operators; first three RFQs the venture receives",
    "threshold": "≥2 of first 3 RFQs requiring SBOM or firmware-security attestation before quotation",
    "updates": "increases"
   },
   {
    "signal": "CRA horizontal-standard timeline for network-connected industrial products",
    "where": "CEN/CENELEC JTC13 docket and Commission CRA implementing-act publications",
    "threshold": "Harmonized standard citing connected power-distribution devices with obligations landing inside the venture's first 24 months",
    "updates": "increases"
   }
  ],
  "judgeTotal": 17
 },
 {
  "riskId": "risk.competitive-foreclosure.framework-agreements-close-first-buyer",
  "title": "The declared 'large operators' beachhead is pre-signed: global framework agreements close the 40% buyer cell before the first sales call",
  "narrative": "The venture's own profile names large operators as the first buyer, and the ledger prices that cell at 0.40 of PDU spend with a comfortable 0.33–0.47 band. But the band models uncertainty about SIZE, not AVAILABILITY. The procurement record shows large operators buying rack power through multi-year global framework agreements and all-in integrated contracts (the Digital Realty–Schneider $373M framework pattern; Iren's all-in Dell deal; Jülich bundling PDU into a single IT line item). A framework agreement is not a competitor to out-sell — it is a contract that removes the tender from the market for its whole term. If a majority of the 0.40 cell is framework-governed, the entrant's declared beachhead is contractually closed for exactly its Year-1 window, and the YAM is silently re-based onto the slower mid-market and channel cells.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "CE large operators renew or extend multi-year global rack-power framework agreements with Schneider/Vertiv/Eaton — the same vendors whose named major customers (Equinix, Telefonica, Vodafone) are the CE operator base",
    "refs": [
     "digest:cust-mix#c12",
     "digest:cr3-vendors#c1",
     "ledger:cust.operator-large"
    ]
   },
   {
    "step": "propagation",
    "text": "PDU line items ride the framework or the integrated OEM package; no standalone, contestable RFQ ever reaches the market for that operator's builds during the term — the entrant's pre-launch, first-12-months window (profile: Stage) coincides with mid-term, not renewal, for most frameworks",
    "refs": [
     "profile:Stage",
     "ledger:cust.operator-large",
     "digest:cust-mix#c0"
    ]
   },
   {
    "step": "model-impact",
    "text": "The addressable fraction of cust.operator-large collapses from 0.40 to roughly the framework-gap residual (~0.20); because the ledger's four channel values are unsourced internal estimates, nothing in the model currently resists this collapse",
    "refs": [
     "ledger:cust.operator-large",
     "ledger:obtainableFactor",
     "digest:cust-mix#c0"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "Global or EMEA rack-power framework renewals announced by Schneider/Vertiv/Eaton with named CE operators",
    "where": "Schneider and Vertiv press rooms; DataCenterDynamics procurement coverage; operator annual reports (supplier commitments notes)",
    "threshold": "Any CE major renewing a ≥3-year rack-power framework during the venture's launch year",
    "updates": "increases"
   },
   {
    "signal": "Standalone rack-PDU lots appearing in European public/colo tenders",
    "where": "TED (tenders.europa.eu) CPV codes for power distribution equipment; national procurement portals (DE: bund.de vergabe)",
    "threshold": "Fewer than 2 standalone, multi-vendor PDU lots per quarter across CE-7",
    "updates": "increases"
   }
  ],
  "judgeTotal": 16
 },
 {
